// Turn any greenLi form payload into a clean subject + email body.
const out = [];
for (const item of $input.all()) {
  const inp = item.json || {};
  // n8n puts the posted JSON under .body; fall back to the root just in case.
  const d = (inp.body && typeof inp.body === 'object') ? inp.body : inp;
  const type = d.formType || 'contact';

  let subject;
  if (type === 'extraction_simulation') subject = 'New extraction simulation request — greenLi website';
  else if (type === 'newsletter') subject = 'New newsletter signup — greenLi website';
  else subject = 'New contact form submission — greenLi website';

  const pretty = (k) => k.replace(/[_-]+/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
  const skip = ['formType', 'sourceUrl'];
  const lines = [];
  for (const k of Object.keys(d)) {
    if (skip.includes(k)) continue;
    const v = d[k];
    if (v === null || v === undefined || v === '') continue;
    lines.push(pretty(k) + ': ' + v);
  }

  const text =
    'Form: ' + type + '\n' +
    'Submitted: ' + new Date().toISOString() + '\n' +
    (d.sourceUrl ? 'Page: ' + d.sourceUrl + '\n' : '') +
    '\n' + lines.join('\n');

  out.push({ json: { to: 'eitan@greenli.biz', subject: subject, text: text } });
}
return out;
